"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getRandomComplete, triggerShake } from "@/lib/learningMessages";

type Tab = "translate" | "rotate";

const GRID_SIZE = 8;
const CELL_SIZE = 40;

// 平移挑战：把图形向右移动3格，向下移动2格
const TRANSLATE_SHAPE = [
  { r: 1, c: 2 },
  { r: 1, c: 3 },
  { r: 2, c: 2 },
  { r: 2, c: 3 },
  { r: 3, c: 2 },
  { r: 3, c: 3 },
]; // 一个2x3的L形变体 - 实际是2x3矩形
const TRANSLATE_TARGET = { dr: 3, dc: 3 }; // 向右3，向下3

// 旋转挑战：把图形顺时针旋转90度
const ROTATE_SHAPE = [
  { r: 1, c: 3 },
  { r: 2, c: 3 },
  { r: 3, c: 3 },
  { r: 3, c: 4 },
  { r: 3, c: 5 },
]; // L形

export default function DrawPage() {
  const [tab, setTab] = useState<Tab>("translate");
  const [translateDone, setTranslateDone] = useState(false);
  const [rotateDone, setRotateDone] = useState(false);
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);

  const allDone = translateDone && rotateDone;

  return (
    <StepShell topicId="motion" stepId="draw">
      <div className="space-y-5">
        {/* 标签切换 */}
        <div className="flex justify-center gap-2">
          <button
            onClick={() => setTab("translate")}
            className={`rounded-full px-5 py-2 text-sm font-medium transition-all ${
              tab === "translate"
                ? "bg-[var(--bg-card)] text-[var(--text)] shadow-[var(--shadow-sm)]"
                : "text-[var(--text-secondary)] hover:bg-[var(--bg-card)]/60"
            }`}
          >
            → 平移画图
            {translateDone && <span className="ml-1 text-[var(--signal-success)]">✓</span>}
          </button>
          <button
            onClick={() => setTab("rotate")}
            className={`rounded-full px-5 py-2 text-sm font-medium transition-all ${
              tab === "rotate"
                ? "bg-[var(--bg-card)] text-[var(--text)] shadow-[var(--shadow-sm)]"
                : "text-[var(--text-secondary)] hover:bg-[var(--bg-card)]/60"
            }`}
          >
            🌀 旋转画图
            {rotateDone && <span className="ml-1 text-[var(--signal-success)]">✓</span>}
          </button>
        </div>

        {/* 平移画图 */}
        {tab === "translate" && !translateDone && (
          <TranslateDrawing onComplete={() => setTranslateDone(true)} />
        )}

        {/* 旋转画图 */}
        {tab === "rotate" && !rotateDone && (
          <RotateDrawing onComplete={() => setRotateDone(true)} />
        )}

        {/* 平移完成 */}
        {tab === "translate" && translateDone && (
          <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
            <div className="text-4xl">→</div>
            <h3 className="mt-3 text-lg font-bold text-[var(--text)]">
              你把图形向右移动了3格
            </h3>
            <p className="mt-2 text-sm text-[var(--text-secondary)]">
              平移后的图形，形状和大小都没变，只是位置变了！
            </p>
            {!rotateDone && (
              <button
                onClick={() => setTab("rotate")}
                className="mt-5 rounded-full bg-[var(--accent)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
              >
                试试旋转画图 →
              </button>
            )}
          </section>
        )}

        {/* 旋转完成 */}
        {tab === "rotate" && rotateDone && (
          <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
            <div className="text-4xl">🌀</div>
            <h3 className="mt-3 text-lg font-bold text-[var(--text)]">
              你把图形顺时针旋转了90度
            </h3>
            <p className="mt-2 text-sm text-[var(--text-secondary)]">
              旋转后的图形，形状和大小也没变，只是方向变了！
            </p>
            {!translateDone && (
              <button
                onClick={() => setTab("translate")}
                className="mt-5 rounded-full bg-[var(--primary)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:scale-105"
              >
                试试平移画图 →
              </button>
            )}
          </section>
        )}

        {/* 全部完成 */}
        {allDone && (
          <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
            <div className="text-5xl animate-bounce-soft">✏️</div>
            <h2 className="mt-3 text-xl font-bold text-[var(--text)]">
              {completeMsg}
            </h2>
            <p className="mt-2 text-[var(--text-secondary)]">
              你学会了画出平移和旋转后的图形！<br />
              不管是平移还是旋转，图形的形状和大小都不变。
            </p>
            <div className="mt-6 flex flex-wrap justify-center gap-3">
              <Link
                href="/learn/motion/transform"
                className="rounded-full bg-[var(--accent)] px-6 py-3 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
              >
                下一步：变一变 →
              </Link>
            </div>
          </section>
        )}
      </div>
    </StepShell>
  );
}

// ========== 平移画图 ==========
function TranslateDrawing({ onComplete }: { onComplete: () => void }) {
  const [cells, setCells] = useState<boolean[][]>(
    Array.from({ length: GRID_SIZE }, () =>
      Array.from({ length: GRID_SIZE }, () => false)
    )
  );
  const [showHint, setShowHint] = useState(false);

  const targetCells = TRANSLATE_SHAPE.map((s) => ({
    r: s.r + TRANSLATE_TARGET.dr,
    c: s.c + TRANSLATE_TARGET.dc,
  }));

  const toggleCell = (r: number, c: number) => {
    setCells((prev) => {
      const next = prev.map((row) => [...row]);
      next[r][c] = !next[r][c];
      return next;
    });
  };

  const checkAnswer = () => {
    // 检查用户画的是否正确
    const userCells: { r: number; c: number }[] = [];
    for (let r = 0; r < GRID_SIZE; r++) {
      for (let c = 0; c < GRID_SIZE; c++) {
        if (cells[r][c]) userCells.push({ r, c });
      }
    }

    if (userCells.length !== targetCells.length) {
      const el = document.getElementById("translate-grid");
      triggerShake(el);
      return;
    }

    const targetSet = new Set(targetCells.map((t) => `${t.r},${t.c}`));
    const allMatch = userCells.every((u) => targetSet.has(`${u.r},${u.c}`));

    if (allMatch) {
      onComplete();
    } else {
      const el = document.getElementById("translate-grid");
      triggerShake(el);
    }
  };

  const filledCount = cells.flat().filter(Boolean).length;

  return (
    <section id="translate-grid" className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
      <div className="text-center">
        <h3 className="text-lg font-bold text-[var(--text)]">平移画图</h3>
        <p className="mt-1 text-sm text-[var(--text-secondary)]">
          把蓝色图形 <span className="font-bold text-[var(--primary)]">向右移 3 格，向下移 3 格</span>
          <br />
          在右边画出平移后的图形
        </p>
      </div>

      {/* 网格 */}
      <div className="mt-5 flex justify-center">
        <div
          className="grid gap-0.5 rounded-lg bg-[var(--border)] p-1"
          style={{
            gridTemplateColumns: `repeat(${GRID_SIZE}, ${CELL_SIZE}px)`,
          }}
        >
          {cells.map((row, r) =>
            row.map((filled, c) => {
              const isOriginal = TRANSLATE_SHAPE.some(
                (s) => s.r === r && s.c === c
              );
              const isHint = showHint && targetCells.some(
                (t) => t.r === r && t.c === c
              );
              return (
                <button
                  key={`${r}-${c}`}
                  onClick={() => toggleCell(r, c)}
                  disabled={isOriginal}
                  className={`aspect-square transition-all ${
                    isOriginal
                      ? "bg-[var(--primary)] cursor-default"
                      : filled
                      ? "bg-[var(--accent2)]"
                      : isHint
                      ? "bg-[var(--accent2)]/30"
                      : "bg-[var(--bg-card)] hover:bg-[var(--bg-soft)]"
                  }`}
                  style={{ width: CELL_SIZE, height: CELL_SIZE }}
                />
              );
            })
          )}
        </div>
      </div>

      <div className="mt-4 text-center">
        <p className="text-sm text-[var(--text-secondary)]">
          已画 <span className="font-bold text-[var(--text)]">{filledCount}</span> 格
          <span className="mx-2 text-[var(--text-muted)]">|</span>
          目标 {TRANSLATE_SHAPE.length} 格
        </p>
      </div>

      <div className="mt-4 flex flex-wrap justify-center gap-3">
        <button
          onClick={() => setShowHint(!showHint)}
          className="rounded-full border border-[var(--border)] px-4 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-soft)]"
        >
          {showHint ? "隐藏提示" : "💡 提示"}
        </button>
        <button
          onClick={() =>
            setCells(
              Array.from({ length: GRID_SIZE }, () =>
                Array.from({ length: GRID_SIZE }, () => false)
              )
            )
          }
          className="rounded-full border border-[var(--border)] px-4 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-soft)]"
        >
          清空
        </button>
        <button
          onClick={checkAnswer}
          className="rounded-full bg-[var(--accent2)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:scale-105"
        >
          检查一下 ✓
        </button>
      </div>
    </section>
  );
}

// ========== 旋转画图 ==========
function RotateDrawing({ onComplete }: { onComplete: () => void }) {
  const [cells, setCells] = useState<boolean[][]>(
    Array.from({ length: GRID_SIZE }, () =>
      Array.from({ length: GRID_SIZE }, () => false)
    )
  );
  const [showHint, setShowHint] = useState(false);
  const [rotation, setRotation] = useState(0);

  // 旋转中心 (3, 3)
  const centerR = 3;
  const centerC = 3;

  // 顺时针旋转90度后的目标位置
  const targetCells = ROTATE_SHAPE.map((s) => {
    // 绕中心点(3,3)顺时针旋转90度
    const dr = s.r - centerR;
    const dc = s.c - centerC;
    // 顺时针90度: (dr, dc) -> (dc, -dr)
    const newR = centerR + dc;
    const newC = centerC - dr;
    return { r: newR, c: newC };
  });

  const toggleCell = (r: number, c: number) => {
    setCells((prev) => {
      const next = prev.map((row) => [...row]);
      next[r][c] = !next[r][c];
      return next;
    });
  };

  const checkAnswer = () => {
    const userCells: { r: number; c: number }[] = [];
    for (let r = 0; r < GRID_SIZE; r++) {
      for (let c = 0; c < GRID_SIZE; c++) {
        if (cells[r][c]) userCells.push({ r, c });
      }
    }

    if (userCells.length !== targetCells.length) {
      const el = document.getElementById("rotate-grid");
      triggerShake(el);
      return;
    }

    const targetSet = new Set(targetCells.map((t) => `${t.r},${t.c}`));
    const allMatch = userCells.every((u) => targetSet.has(`${u.r},${u.c}`));

    if (allMatch) {
      onComplete();
    } else {
      const el = document.getElementById("rotate-grid");
      triggerShake(el);
    }
  };

  const filledCount = cells.flat().filter(Boolean).length;

  // 预览旋转动画
  const previewRotate = () => {
    setRotation(90);
    setTimeout(() => setRotation(0), 1500);
  };

  return (
    <section id="rotate-grid" className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
      <div className="text-center">
        <h3 className="text-lg font-bold text-[var(--text)]">旋转画图</h3>
        <p className="mt-1 text-sm text-[var(--text-secondary)]">
          把蓝色图形绕红点 <span className="font-bold text-[var(--accent)]">顺时针旋转 90 度</span>
          <br />
          画出旋转后的图形
        </p>
      </div>

      {/* 旋转预览按钮 */}
      <div className="mt-3 flex justify-center">
        <button
          onClick={previewRotate}
          className="rounded-full bg-[var(--accent)]/20 px-4 py-1.5 text-xs font-medium text-[var(--accent)] transition-colors hover:bg-[var(--accent)]/30"
        >
          🎬 看看怎么转的
        </button>
      </div>

      {/* 网格 */}
      <div className="mt-4 flex justify-center">
        <div
          className="relative grid gap-0.5 rounded-lg bg-[var(--border)] p-1"
          style={{
            gridTemplateColumns: `repeat(${GRID_SIZE}, ${CELL_SIZE}px)`,
          }}
        >
          {cells.map((row, r) =>
            row.map((filled, c) => {
              const isOriginal = ROTATE_SHAPE.some(
                (s) => s.r === r && s.c === c
              );
              const isCenter = r === centerR && c === centerC;
              const isHint = showHint && targetCells.some(
                (t) => t.r === r && t.c === c
              );
              return (
                <button
                  key={`${r}-${c}`}
                  onClick={() => toggleCell(r, c)}
                  disabled={isOriginal}
                  className={`relative aspect-square transition-all ${
                    isOriginal
                      ? "bg-[var(--primary)] cursor-default"
                      : filled
                      ? "bg-[var(--accent)]"
                      : isHint
                      ? "bg-[var(--accent)]/30"
                      : "bg-[var(--bg-card)] hover:bg-[var(--bg-soft)]"
                  }`}
                  style={{
                    width: CELL_SIZE,
                    height: CELL_SIZE,
                    transform: isOriginal && rotation > 0 ? `rotate(${rotation}deg)` : "none",
                    transformOrigin: `${(centerC - c + 0.5) * CELL_SIZE}px ${(centerR - r + 0.5) * CELL_SIZE}px`,
                    transition: "transform 1s ease-in-out",
                  }}
                >
                  {isCenter && (
                    <span className="absolute inset-0 flex items-center justify-center">
                      <span className="h-3 w-3 rounded-full bg-[var(--accent)] ring-2 ring-white" />
                    </span>
                  )}
                </button>
              );
            })
          )}
        </div>
      </div>

      <div className="mt-4 text-center">
        <p className="text-sm text-[var(--text-secondary)]">
          已画 <span className="font-bold text-[var(--text)]">{filledCount}</span> 格
          <span className="mx-2 text-[var(--text-muted)]">|</span>
          目标 {ROTATE_SHAPE.length} 格
        </p>
      </div>

      <div className="mt-4 flex flex-wrap justify-center gap-3">
        <button
          onClick={() => setShowHint(!showHint)}
          className="rounded-full border border-[var(--border)] px-4 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-soft)]"
        >
          {showHint ? "隐藏提示" : "💡 提示"}
        </button>
        <button
          onClick={() =>
            setCells(
              Array.from({ length: GRID_SIZE }, () =>
                Array.from({ length: GRID_SIZE }, () => false)
              )
            )
          }
          className="rounded-full border border-[var(--border)] px-4 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-soft)]"
        >
          清空
        </button>
        <button
          onClick={checkAnswer}
          className="rounded-full bg-[var(--accent)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
        >
          检查一下 ✓
        </button>
      </div>
    </section>
  );
}
